import { createTheme } from "@mui/material/styles";


const appTheme = createTheme({
    typography: {
        h1: {
          fontFamily: 'Avenir',
          fontSize: '24px',
          fontWeight: 900,
          lineHeight: '32px'
        },
        h2: {
          fontFamily: 'Avenir',
          fontSize: '16px',
          fontWeight: 900,
        },
        
        
      },
      palette: {
        primary: {
            main: '#779A4A',
            dark: '#425D07',
            light: '#8D6542',
            background: '#779a4a80',
            contrastText: '#FFFFFF'
        },
      },
      components: {
        MuiCssBaseline: {
          styleOverrides: `
          @font-face {
            font-family: 'Avenir';
            src: url(fonts/AvenirLTStd-Black.otf) format('otf'); 
            weight: 900;
            font-style: normal;
          }
          `,
        },
      }
});

export default appTheme;
